Bash(node -e "
const CS = 28;
const GHOST_SPEED = 2.0;

function toCol\(px\) { return Math.round\(\(px - CS/2\) / CS\); }
function toRow\(py\) { return Math.round\(\(py - CS/2\) / CS\); }
function cellCenter\(c, r\) { return { x: c*CS+CS/2, y: r*CS+CS/2 }; }

// Blinky starts at col=10, row=9
let g = { x: 294, y: 266, dir: 'LEFT' };
console.log\('--- Blinky first 5 ticks ---'\);
for \(let t = 0; t < 5; t++\) {
  const col = toCol\(g.x\), row = toRow\(g.y\);
  const cx = cellCenter\(col, row\);
  const aligned = Math.abs\(g.x - cx.x\) < GHOST_SPEED+1 && Math.abs\(g.y - cx.y\) < GHOST_SPEED+1;
  console.log\('tick', t, 'pos=\('+g.x+','+g.y+'\) col='+col+' aligned='+aligned+' cx.x='+cx.x\);
  if \(aligned\) { g.x = cx.x; g.y = cx.y; } // snap
  g.x += -1 * GHOST_SPEED; // move LEFT
}
")

